cs","1 working day decision target"]}]},"about":[{"label":"Description","value":"Student Route visa for study at a UK institution holding a valid sponsor licence. Requires Confirmation of Acceptance for Studies (CAS) and online UKVI application."},{"label":"Eligible applicants","value":"Valid CAS · Proof of funds · English at required level · Genuine student intent · TB test if from listed country"},{"label":"Financial requirement","value":"Tuition minus deposit paid + living costs (London vs outside London rates). 28-day funds rule applies.","warning":true},{"label":"Key authority","value":"UK Visas and Immigration (UKVI) — Home Office"},{"label":"After approval","value":"BRP or digital status; maintain attendance, sponsor reporting, and work hour limits."}],"eligibility":[{"criterion":"CAS from licensed UK sponsor","met":true,"note":"CAS number valid and unused"},{"criterion":"Financial requirement met (28-day rule)","met":true,"note":"Funds held 28 consecutive days"},{"criterion":"English language at SELT level (if required)","met":true,"note":"IELTS UKVI or exempt pathway"},{"criterion":"TB test certificate (if applicable)","met":false,"note":"Required for Indian nationals"},{"criterion":"ATAS certificate (if course requires)","met":false,"note":"Check CAS and course code"},{"criterion":"Genuine student / credible study plan","met":true},{"criterion":"Immigration history disclosed","met":true}],"redFlagsBanner":"After refusal, analyse refusal letter and address specific grounds before reapplication with new CAS if needed.","redFlags":[{"title":"28-day funds rule breach","description":"Funds not held continuously for 28 days or balance drops below threshold.","fix":"Maintain required balance 28 days; use dated bank statements","severity":"Very common"},{"title":"CAS / course mismatch","description":"Course level inconsistent with prior study or career plan.","fix":"Align CAS course with academic progression; strong personal statement","severity":"Common"},{"title